			dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				newAssignIdx := dispatch.AssignsLen
				dispatch.Assigns[newAssignIdx].AddShip(orderID, oris[orderIdx], dess[orderIdx])
				dispatch.Assigns[newAssignIdx].GenRoute()
				if dispatch.Assigns[newAssignIdx].Cost >= 0 {
					dispatch.AssignsLen++
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}
